function updateParticipant(e,t){if(!e)return;const s=e.getElementsByClassName("name")[0];if(t?.id!=null){e.setAttribute("data-participant-id",t.id.toString());const r=bracketsViewer.participants.find(d=>d.id===t.id);r&&(e.setAttribute("title",r.name),s.innerHTML=r.name,bracketsViewer.renderParticipantImage(s,r.id))}else e.setAttribute("data-participant-id",""),e.setAttribute("title",""),s.innerHTML="";t?.result==="win"?(e.classList.add("win"),e.classList.remove("loss")):t?.result==="loss"?(e.classList.add("loss"),e.classList.remove("win")):(e.classList.remove("win"),e.classList.remove("loss"));const i=e.querySelector(".result");i&&(i.innerHTML=t?.score?t.score.toString():"-")}function updateMatch(e,t){const s=document.getElementById(e);if(!s)throw Error("Element not found.");s.querySelectorAll(".match").forEach(i=>{i.getAttribute("data-match-id")===t.id.toString()&&(updateParticipant(i.querySelector(".participant:nth-of-type(1)"),t.opponent1),updateParticipant(i.querySelector(".participant:nth-of-type(2)"),t.opponent2))})}HTMLWidgets.shinyMode&&Shiny.addCustomMessageHandler("updateBracketsViewer",function(e){const t=e.id+"-brackets-viewer";e.data&&updateMatch(t,e.data),e.theme&&applyTheme(t,e.theme)});
